# Configuration from environment variables
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<storage-account>.blob.core.windows.net")
STORAGE_CONTAINER_NAME = os.environ.get("STORAGE_CONTAINER_NAME", "input-files")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<cosmos-account>.documents.azure.com:443/")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "processingdb")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "results")
EVENTGRID_TOPIC_ENDPOINT = os.environ.get("EVENTGRID_TOPIC_ENDPOINT", "https://<topic-name>.<region>.eventgrid.azure.net/api/events")
MANAGED_IDENTITY_CLIENT_ID = os.environ.get("MANAGED_IDENTITY_CLIENT_ID", None)

app = func.FunctionApp()


def get_credential():
    """
    Get Azure credential using Managed Identity.
    
    SECURITY NOTE: This MVP uses broad permissions for rapid development:
    - Storage Blob Data Contributor (read/write/delete blobs)
    - Cosmos DB Account Contributor (full Cosmos DB access)
    - Event Grid Data Sender (publish events)
    
    TODO (before production):
    - Apply least-privilege principle:
      - Use Storage Blob Data Reader if only reading blobs
      - Use custom Cosmos DB RBAC roles scoped to specific databases/containers
      - Scope Event Grid permissions to specific topics
    - Use user-assigned managed identity with MANAGED_IDENTITY_CLIENT_ID
    - Add network restrictions (private endpoints, VNet integration)
    - Enable diagnostic logging and auditing
    - Rotate any fallback credentials regularly
    """
    if MANAGED_IDENTITY_CLIENT_ID:
        # Use user-assigned managed identity (more explicit, recommended)
        return ManagedIdentityCredential(client_id=MANAGED_IDENTITY_CLIENT_ID)
    else:
        # Falls back to system-assigned managed identity, env vars, Azure CLI, etc.
        return DefaultAzureCredential()


def get_blob_service_client() -> BlobServiceClient:
    """Initialize Blob Storage client with Managed Identity."""
    credential = get_credential()
    return BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)


def get_cosmos_client() -> CosmosClient:
    """Initialize Cosmos DB client with Managed Identity."""
    credential = get_credential()
    return CosmosClient(url=COSMOS_ENDPOINT, credential=credential)


def get_eventgrid_client() -> EventGridPublisherClient:
    """Initialize Event Grid client with Managed Identity."""
    credential = get_credential()
    return EventGridPublisherClient(endpoint=EVENTGRID_TOPIC_ENDPOINT, credential=credential)


def ensure_cosmos_database_and_container(cosmos_client: CosmosClient):
    """Ensure the Cosmos DB database and container exist."""
    database = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
    container = database.create_container_if_not_exists(
        id=COSMOS_CONTAINER_NAME,
        partition_key=PartitionKey(path="/partitionKey"),
        offer_throughput=400
    )
    return database, container


def process_blob_content(blob_name: str, content: bytes) -> dict:
    """
    Process the blob content and return structured results.
    
    This is the core business logic - customize based on your use case.
    """
    content_str = content.decode("utf-8", errors="replace")
    
    # Example processing: analyze the file content
    result = {
        "fileName": blob_name,
        "fileSize": len(content),
        "lineCount": content_str.count("\n") + 1 if content_str else 0,
        "wordCount": len(content_str.split()) if content_str else 0,
        "charCount": len(content_str),
        "processedAt": datetime.datetime.utcnow().isoformat(),
        "status": "processed",
        "contentPreview": content_str[:500] if content_str else "",
    }
    
    # Add content-type specific processing
    if blob_name.endswith(".json"):
        try:
            parsed = json.loads(content_str)
            result["jsonValid"] = True
            result["jsonKeys"] = list(parsed.keys()) if isinstance(parsed, dict) else None
            result["jsonItemCount"] = len(parsed) if isinstance(parsed, (list, dict)) else None
        except json.JSONDecodeError as e:
            result["jsonValid"] = False
            result["jsonError"] = str(e)
    elif blob_name.endswith(".csv"):
        lines = content_str.strip().split("\n")
        if lines:
            result["csvColumns"] = lines[0].split(",") if lines else []
            result["csvRowCount"] = len(lines) - 1  # Exclude header
    
    return result


def write_to_cosmos(container, blob_name: str, processing_result: dict) -> dict:
    """Write processing results to Cosmos DB."""
    document = {
        "id": f"{blob_name}-{datetime.datetime.utcnow().strftime('%Y%m%d%H%M%S%f')}",
        "partitionKey": blob_name.split("/")[0] if "/" in blob_name else "default",
        "blobName": blob_name,
        "result": processing_result,
        "createdAt": datetime.datetime.utcnow().isoformat(),
        "ttl": -1,  # No expiration; set to seconds for auto-cleanup
    }
    
    created_item = container.create_item(body=document)
    logging.info(f"Document written to Cosmos DB with id: {created_item['id']}")
    return created_item


def send_eventgrid_notification(client: EventGridPublisherClient, blob_name: str, 
                                 processing_result: dict, cosmos_document_id: str):
    """Send processing completion notification via Event Grid."""
    event = CloudEvent(
        type="BlobProcessing.Completed",
        source=f"/azure/functions/blob-processor",
        data={
            "blobName": blob_name,
            "status": processing_result.get("status", "unknown"),
            "fileSize": processing_result.get("fileSize", 0),
            "cosmosDocumentId": cosmos_document_id,
            "processedAt": processing_result.get("processedAt", ""),
            "summary": {
                "lineCount": processing_result.get("lineCount", 0),
                "wordCount": processing_result.get("wordCount", 0),
            }
        },
        subject=f"blob/{blob_name}",
    )
    
    client.send([event])
    logging.info(f"Event Grid notification sent for blob: {blob_name}")


