@app.blob_trigger(
    arg_name="myblob",
    path=f"{STORAGE_CONTAINER_NAME}/{{name}}",
    connection="AzureWebJobsStorage"
)
def blob_trigger_processor(myblob: func.InputStream):
    """
    Triggered when a new blob is uploaded to the configured container.
    Processes the blob, writes results to Cosmos DB, and sends Event Grid notification.
    """
    blob_name = myblob.name
    logging.info(f"Blob trigger fired for: {blob_name}, Size: {myblob.length} bytes")
    
    try:
        # Read blob content
        content = myblob.read()
        logging.info(f"Read {len(content)} bytes from blob: {blob_name}")
        
        # Process the blob content
        processing_result = process_blob_content(blob_name, content)
        logging.info(f"Processing complete for: {blob_name}")
        
        # Write results to Cosmos DB
        cosmos_client = get_cosmos_client()
        _, container = ensure_cosmos_database_and_container(cosmos_client)
        cosmos_doc = write_to_cosmos(container, blob_name, processing_result)
        logging.info(f"Results written to Cosmos DB for: {blob_name}")
        
        # Send Event Grid notification
        try:
            eg_client = get_eventgrid_client()
            send_eventgrid_notification(eg_client, blob_name, processing_result, cosmos_doc["id"])
        except Exception as eg_error:
            # Don't fail the whole function if Event Grid notification fails
            logging.error(f"Event Grid notification failed for {blob_name}: {eg_error}")
        
        logging.info(f"Successfully processed blob: {blob_name}")
        
    except Exception as e:
        logging.error(f"Error processing blob {blob_name}: {e}", exc_info=True)
        
        # Attempt to write error to Cosmos DB for tracking
        try:
            cosmos_client = get_cosmos_client()
            _, container = ensure_cosmos_database_and_container(cosmos_client)
            error_doc = {
                "id": f"error-{blob_name}-{datetime.datetime.utcnow().strftime('%Y%m%d%H%M%S%f')}",
                "partitionKey": "errors",
                "blobName": blob_name,
                "error": str(e),
                "status": "failed",
                "createdAt": datetime.datetime.utcnow().isoformat(),
            }
            container.create_item(body=error_doc)
        except Exception as cosmos_error:
            logging.error(f"Failed to write error to Cosmos DB: {cosmos_error}")
        
        raise


@app.route(route="process/{blob_name}", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def http_trigger_processor(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered function to manually process a specific blob.
    POST /api/process/{blob_name}
    """
    blob_name = req.route_params.get("blob_name")
    
    if not blob_name:
        return func.HttpResponse(
            json.dumps({"error": "blob_name is required in the route"}),
            status_code=400,
            mimetype="application/json"
        )
    
    logging.info(f"HTTP trigger: Processing blob: {blob_name}")
    
    try:
        # Read blob from storage using Managed Identity
        blob_service_client = get_blob_service_client()
        blob_client = blob_service_client.get_blob_client(
            container=STORAGE_CONTAINER_NAME,
            blob=blob_name
        )
        
        if not blob_client.exists():
            return func.HttpResponse(
                json.dumps({"error": f"Blob '{blob_name}' not found in container '{STORAGE_CONTAINER_NAME}'"}),
                status_code=404,
                mimetype="application/json"
            )
        
        download_stream = blob_client.download_blob()
        content = download_stream.readall()
        logging.info(f"Downloaded {len(content)} bytes from blob: {blob_name}")
        
        # Process the blob content
        processing_result = process_blob_content(blob_name, content)
        
        # Write results to Cosmos DB
        cosmos_client = get_cosmos_client()
        _, container = ensure_cosmos_database_and_container(cosmos_client)
        cosmos_doc = write_to_cosmos(container, blob_name, processing_result)
        
        # Send Event Grid notification
        try:
            eg_client = get_eventgrid_client()
            send_eventgrid_notification(eg_client, blob_name, processing_result, cosmos_doc["id"])
        except Exception as eg_error:
            logging.error(f"Event Grid notification failed: {eg_error}")
            processing_result["eventGridNotification"] = "failed"
        
        response_body = {
            "status": "success",
            "blobName": blob_name,
            "cosmosDocumentId": cosmos_doc["id"],
            "result": processing_result,
        }
        
        return func.HttpResponse(
            json.dumps(response_body, default=str),
            status_code=200,
            mimetype="application/json"
        )
        
    except Exception as e:
        logging.error(f"Error processing blob {blob_name}: {e}", exc_info=True)
        return func.HttpResponse(
            json.dumps({"error": str(e), "blobName": blob_name}),
            status_code=500,
            mimetype="application/json"
        )


@app.route(route="list-results", methods=["GET"], auth_level=func.AuthLevel.FUNCTION)
def list_processing_results(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered function to list recent processing results from Cosmos DB.
    GET /api/list-results?limit=10&status=processed
    """
    limit = req.params.get("limit", "10")
    status_filter = req.params.get("status", None)
    
    try:
        limit = min(int(limit), 100)
    except ValueError:
        limit = 10
    
    try:
        cosmos_client = get_cosmos_client()
        _, container = ensure_cosmos_database_and_container(cosmos_client)
        
        if status_filter:
            query = f"SELECT TOP {limit} * FROM c WHERE c.result.status = @status ORDER BY c.createdAt DESC"
            parameters = [{"name": "@status", "value": status_filter}]
        else:
            query = f"SELECT TOP {limit} * FROM c ORDER BY c.createdAt DESC"
            parameters = None
        
        items = list(container.query_items(
            query=query,
            parameters=parameters,
            enable_cross_partition_query=True,
        ))
        
        return func.HttpResponse(
            json.dumps({"count": len(items), "results": items}, default=str),
            status_code=200,
            mimetype="application/json"
        )
        
    except Exception as e:
        logging.error(f"Error listing results: {e}", exc_info=True)
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            status_code=500,
            mimetype="application/json"
        )


@app.route(route="health", methods=["GET"], auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint that verifies connectivity to all services."""
    health_status = {
        "function": "healthy",
        "timestamp": datetime.datetime.utcnow().isoformat(),
        "services": {}
    }
    
    overall_healthy = True
    
    # Check Blob Storage
    try:
        blob_service_client = get_blob_service_client()
        container_client = blob_service_client.get_container_client(STORAGE_CONTAINER_NAME)
        container_client.get_container_properties()
        health_status["services"]["blobStorage"] = "healthy"
    except Exception as e:
        health_status["services"]["blobStorage"] = f"unhealthy: {str(e)}"
        overall_healthy = False
    
    # Check Cosmos DB
    try:
        cosmos_client = get_cosmos_client()
        _, container = ensure_cosmos_database_and_container(cosmos_client)
        # Simple query to verify connectivity
        list(container.query_items(
            query="SELECT TOP 1 c.id FROM c",
            enable_cross_partition_query=True,
        ))
        health_status["services"]["cosmosDb"] = "healthy"
    except Exception as e:
        health_status["services"]["cosmosDb"] = f"unhealthy: {str(e)}"
        overall_healthy = False
    
    # Check Event Grid (just verify client creation, no test event)
    try:
        _ = get_eventgrid_client()
        health_status["services"]["eventGrid"] = "client_initialized"
    except Exception as e:
        health_status["services"]["eventGrid"] = f"unhealthy: {str(e)}"
        overall_healthy = False
    
    health_status["overall"] = "healthy" if overall_healthy else "degraded"
    status_code = 200 if overall_healthy else 503
    
    return func.HttpResponse(
        json.dumps(health_status, default=str),
        status_code=status_code,
        mimetype="application/json"
    )


